using Microsoft.AspNetCore.Hosting;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Drawing;
using System.IO;
using System.Drawing.Imaging;
using System.Drawing.Drawing2D;
using PagamentoApi.Models.Partial;
using QRCoder;
using System.Net;
using AutoMapper.Configuration;
using PagamentoApi.Repositories;
using PagamentoApi.Settings;

namespace PagamentoApi.Services
{
    public class CartaoVirtual
    {
        private static ImageConverter _imageConverter = new ImageConverter();

        public static string GeraCredencial(ClientelaApp cliente)
        {
            var fotoDefault = Convert.FromBase64String("");
            var img64Pleno = "";
            var img64Atividade = "";
            var fundo = cliente.TipoCategoria < 2 ? img64Pleno : img64Atividade; //OBTENDO LAYOUT DE FUNDO DE ACORDO COM TIPO DO CLIENTE
            var ypositionCategoria = 940; //DEFININDO MARGEM PARA DESCRIÇÃO DA CATEGORIA
            
            var fotoDb2 = GetImageFromByteArray(cliente.FOTO is null ? fotoDefault : cliente.FOTO, 300, 300); //OBTENDO IMAGEM DO BYTE[] DE IMAGEM
            
            var fotoResize = ResizeImage(fotoDb2, 130, 150); //REAJUSTANDO TAMANHO DA IMAGEM
            var fotoRounded = RoundCorners(fotoResize, 65, Color.Transparent); //APLICANDO ESTILO ARREDONDADO NOS CANTOS
            //var arquivoBase64 = Convert.ToBase64String(imageAsByteArray); //LENDO ARQUIVO DE FUNDO E CONVERTENDO PARA BASE64
            var arquivoBase64 = fundo; //LENDO ARQUIVO DE FUNDO E CONVERTENDO PARA BASE64
            var imagemfundo = Image.FromStream(new MemoryStream(Convert.FromBase64String(arquivoBase64))); //CONVERTENDO BASE64 DO FUNDO PARA IMAGEM NA MEMORIA
            var gr = Graphics.FromImage(imagemfundo); //EXTRAINDO GRAFICOS DA IMAGEM DE FUNDO

            //VERIFICANDO CODIGO DE BARRAS DO CLIENTE
            if (cliente.Cdbarras != null)
            {               
                var cdbarras = GeneratedQRCode(Convert.ToInt64(cliente.Cdbarras).ToString()); //COnVERTE CDBRRAS PARA BASE64
                var qr = GetImageFromByteArray(cdbarras, 300, 300); //CONVERTE BYTE[] PARA TIPO IMAGEM
                var qrcode = ResizeImage(qr, 320, 320); //REAJUSTA TAMANHO DO QRCODE
                gr.DrawImage(qrcode, new PointF(240, 1060));
            }

            var vencimento = $"{cliente.DTVENCTO.ToShortDateString().Split('/')[1]}/{cliente.DTVENCTO.ToShortDateString().Split('/')[2]}"; //PEGA MES E ANO DO VENCIMENTO

            #region Formatando texto
            //APLICANDO ESTILOS AOS TEXTOS
            StringFormat center = new StringFormat();
            center.LineAlignment = StringAlignment.Center;
            center.Alignment = StringAlignment.Center;
            #endregion

            #region Adicionando/desenhando imagens e texto
            gr.DrawImage(fotoRounded, new PointF(200, 270)); //ADICIONANDO FOTO
            gr.DrawString(cliente.NMCLIENTE.Split(" ")[0] + " " + cliente.NMCLIENTE.Split(" ")[1], new Font("Mulish", 12, FontStyle.Bold), Brushes.Black, new PointF(400, 720), center); //ADICIONANDO NOME DO CLIENTE
            //gr.DrawString(cliente.NMCLIENTE.Split(" ")[0], new Font("Mulish", 12, FontStyle.Bold), Brushes.Black, new PointF(400, 720), center); //ADICIONANDO NOME DO CLIENTE
            gr.DrawString(cliente.DTNASCIMEN.ToShortDateString(), new Font("Mulish", 8), Brushes.Black, new PointF(400, 780), center); //ADICIONANDO DATA DE NASCIMENTO

            if (cliente.TipoCategoria < 2)
            {
                gr.DrawString("Credencial Plena", new Font("Mulish", 11, FontStyle.Bold), Brushes.Black, new PointF(400, 880), center);
            }
            else
            {
                gr.DrawString("Credencial Atividades", new Font("Mulish", 11, FontStyle.Bold), Brushes.Black, new PointF(400, 880), center);
            }

            //PROCESSANDO DESCRIÇÃO DE CATEGORIA COM QUEBRA DE LINHA
            if (cliente.CDCATEGORI == 25)
            {
                cliente.Categoria = "TRABALHADOR DO COMÉRCIO";
            }
            if (cliente.CDCATEGORI == 22)
            {
                cliente.Categoria = "DEPENDENTE TRABALHADOR DO COMÉRCIO";
            }
            var linhasCategoria = MakeRows(cliente.Categoria);
            foreach (var linha in linhasCategoria)
            {
                gr.DrawString(linha, new Font("Mulish", 10), Brushes.Black, new PointF(400, ypositionCategoria), center);
                ypositionCategoria = ypositionCategoria + 50;
            }

            gr.DrawString(cliente.Matricula, new Font("Mulish", 8), Brushes.Black, new PointF(400, 1070), center); //ADICIONANDO MATRICULA
            gr.DrawString("Validade nacional: ", new Font("Mulish", 7), Brushes.Black, new PointF(330, 1360), center);
            gr.DrawString(vencimento, new Font("Mulish", 7, FontStyle.Bold), Brushes.Black, new PointF(540, 1360), center);
            gr.DrawString("AR/AMAPA", new Font("Mulish", 7, FontStyle.Bold), Brushes.Black, new PointF(400, 1390), center);

            #endregion

            #region convertendo imagem final para base64
            byte[] imageBytes;
            using (MemoryStream ms = new MemoryStream())
            {
                imagemfundo.Save(ms, ImageFormat.Jpeg);
                imageBytes = ms.ToArray();
                string base64String = Convert.ToBase64String(imageBytes);
                return base64String;
            }
            #endregion
        }
        public static List<string> MakeRows(string categoria)
        {
            categoria = categoria.Trim();
            var qtdEspacos = categoria.Split(' ').Length;
            var linhasCategoria = new List<string>();

            switch (qtdEspacos)
            {
                case 1:
                    linhasCategoria.Add($"{categoria.Split(' ')[0]}");
                    break;
                case 2:
                    linhasCategoria.Add($"{categoria.Split(' ')[0]} {categoria.Split(' ')[1]}");
                    break;
                case 3:
                    linhasCategoria.Add($"{categoria.Split(' ')[0]} {categoria.Split(' ')[1]}");
                    linhasCategoria.Add($"{categoria.Split(' ')[2]}");
                    break;
                case 4:
                    linhasCategoria.Add($"{categoria.Split(' ')[0]} {categoria.Split(' ')[1]}");
                    linhasCategoria.Add($"{categoria.Split(' ')[2]} {categoria.Split(' ')[3]}");
                    break;
                case 5:
                    linhasCategoria.Add($"{categoria.Split(' ')[0]} {categoria.Split(' ')[1]}");
                    linhasCategoria.Add($"{categoria.Split(' ')[2]} {categoria.Split(' ')[3]} {categoria.Split(' ')[4]}");
                    break;
                default:
                    linhasCategoria.Add($"{categoria.Split(' ')[0]}");
                    break;
            }

            return linhasCategoria;
        }

        public static Image RoundCorners(Image StartImage, int CornerRadius, Color BackgroundColor)
        {
            CornerRadius *= 2;
            Bitmap RoundedImage = new Bitmap(130, 130);
            using (Graphics g = Graphics.FromImage(RoundedImage))
            {
                g.Clear(BackgroundColor);
                g.SmoothingMode = SmoothingMode.AntiAlias;
                Brush brush = new TextureBrush(StartImage);
                GraphicsPath gp = new GraphicsPath();
                gp.AddArc(0, 0, CornerRadius, CornerRadius, 180, 90);
                gp.AddArc(0 + RoundedImage.Width - CornerRadius, 0, CornerRadius, CornerRadius, 270, 90);
                gp.AddArc(0 + RoundedImage.Width - CornerRadius, 0 + RoundedImage.Height - CornerRadius, CornerRadius, CornerRadius, 0, 90);
                gp.AddArc(0, 0 + RoundedImage.Height - CornerRadius, CornerRadius, CornerRadius, 90, 90);
                g.FillPath(brush, gp);
                return RoundedImage;
            }
        }
        public static byte[] GeneratedQRCode(string url)
        {
            QRCodeGenerator qrGenerator = new QRCodeGenerator();
            QRCodeData qrCodeData = qrGenerator.CreateQrCode(url, QRCodeGenerator.ECCLevel.Q);
            QRCode qrCode = new QRCode(qrCodeData);
            Bitmap qrCodeImage = qrCode.GetGraphic(20, Color.Black, Color.Transparent, true);

            using (var stream = new MemoryStream())
            {
                qrCodeImage.Save(stream, System.Drawing.Imaging.ImageFormat.Png);
                return stream.ToArray();
            }
        }
        public static Bitmap GetImageFromByteArray(byte[] byteArray, int xdpi, int ydpi)
        {
            Bitmap bm = (Bitmap)_imageConverter.ConvertFrom(byteArray);

            bm.SetResolution(xdpi, ydpi);
            return bm;
        }
        public static Bitmap ResizeImage(Image image, int width, int height)
        {
            var destRect = new Rectangle(0, 0, width, height);
            var destImage = new Bitmap(width, height);

            destImage.SetResolution(image.HorizontalResolution, image.VerticalResolution);

            using (var graphics = Graphics.FromImage(destImage))
            {
                graphics.CompositingMode = CompositingMode.SourceCopy;
                graphics.CompositingQuality = CompositingQuality.HighQuality;
                graphics.InterpolationMode = InterpolationMode.HighQualityBicubic;
                graphics.SmoothingMode = SmoothingMode.HighQuality;
                graphics.PixelOffsetMode = PixelOffsetMode.HighQuality;

                using (var wrapMode = new ImageAttributes())
                {
                    wrapMode.SetWrapMode(WrapMode.TileFlipXY);
                    graphics.DrawImage(image, destRect, 0, 0, image.Width, image.Height, GraphicsUnit.Pixel, wrapMode);
                }
            }

            return destImage;
        }
    }
}
